import pandas as pd

def resumen_por_participante(datos: pd.DataFrame) -> pd.DataFrame:
    requeridas = {'participante', 'valor'}
    if not requeridas.issubset(datos.columns):
        raise ValueError('faltan columnas')
    limpio = datos.dropna(subset=['participante', 'valor']).copy()
    por_persona = (
        limpio.groupby('participante', as_index=False)['valor']
        .mean()
        .rename(columns={'valor': 'media_personal'})
    )
    return por_persona
